class Helper:
    def __init__(self):
        self.ALLOWED = True
        self.RESULT = {'type': '', 'dict': '', 'iter': 0, 'pwd': '', 'salt': ''}
        self.__DICT_LIST = []
        self.__type = ''
        self.__salt = ''
        self.__hash = ''

    def log_error(self, f):
